use actix_files as fs;
use actix_web::{web, App, HttpRequest, HttpServer, Result};
use std::path::PathBuf;

async fn serve_file(req: HttpRequest) -> Result<fs::NamedFile> {
    let filename: PathBuf = req.match_info().query("filename").parse().unwrap();
    let filepath = PathBuf::from("./uploads/").join(filename);
    Ok(fs::NamedFile::open(filepath)?)
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new().route("/{filename:.*}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}